#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-21

# =============================================================================
# Budget governor self-test — deterministic, $0, no LLM calls
# =============================================================================
# The governor exists to stop an eval run that cannot possibly succeed. Its own
# failure mode is blocking a run that WOULD have succeeded, so the important
# cases here are the negative ones: unparseable message, expired reset, absent
# state. Each must PROCEED.
# =============================================================================
set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
export REPO_ROOT
# shellcheck source=/dev/null
source "$REPO_ROOT/tests/evals/scripts/lib/budget-governor.sh"

STATE="$REPO_ROOT/tests/evals/results/.budget-state.json"
BACKUP=""
[[ -f "$STATE" ]] && { BACKUP="$(mktemp)"; cp "$STATE" "$BACKUP"; }
restore() {
  if [[ -n "$BACKUP" ]]; then cp "$BACKUP" "$STATE"; rm -f "$BACKUP"; else rm -f "$STATE"; fi
}
trap restore EXIT

PASSED=0; FAILED=0
ok()   { printf '  \033[0;32mok\033[0m   %s\n' "$1"; PASSED=$((PASSED+1)); }
bad()  { printf '  \033[0;31mFAIL\033[0m %s\n' "$1"; FAILED=$((FAILED+1)); }
check(){ [[ "$2" == "$3" ]] && ok "$1" || bad "$1 (want '$3', got '$2')"; }

# BSD date uses -r for epoch input, GNU uses -d @epoch. Try both.
epoch_hour() {
  local e="$1" h
  # silent: external-api-shape
  h=$(date -u -r "$e" '+%H' 2>/dev/null || true)
  if [[ -z "$h" ]]; then
    # silent: external-api-shape
    h=$(date -u -d "@$e" '+%H' 2>/dev/null || true)
  fi
  printf '%s' "$h"
}

echo "=========================================="
echo "  Budget Governor Self-Test"
echo "=========================================="
echo ""

echo "-- parsing --"
check "weekly message yields an epoch" \
  "$([[ -n "$(_bg_parse_reset_epoch "You've hit your weekly limit    resets Jul 21, 11pm (UTC)")" ]] && echo yes || echo no)" "yes"
check "bare epoch form is read" \
  "$(_bg_parse_reset_epoch 'Claude AI usage limit reached|1784500000')" "1784500000"
check "message with no reset clause yields nothing" \
  "$(_bg_parse_reset_epoch 'something else entirely')" ""
check "11pm maps to hour 23" \
  "$(epoch_hour "$(_bg_parse_reset_epoch 'resets Jul 21, 11pm (UTC)')")" "23"

echo ""
echo "-- classification --"
rm -f "$STATE"
record_cap_exhausted "You've hit your weekly limit    resets Jul 21, 11pm (UTC)"
check "weekly cap classified" "$(jq -r '.kind' "$STATE")" "weekly"
record_cap_exhausted "API rate limit exceeded, please retry"
check "rolling limit classified" "$(jq -r '.kind' "$STATE")" "rolling"
record_cap_exhausted "totally unrecognised text"
check "unknown shape classified" "$(jq -r '.kind' "$STATE")" "unknown"
check "unknown shape records null reset" "$(jq -r '.reset_epoch' "$STATE")" "null"

echo ""
echo "-- gating (the cases that must PROCEED) --"
rm -f "$STATE"
set +e; budget_check >/dev/null 2>&1; rc=$?; set -e
check "no state file proceeds" "$rc" "0"

record_cap_exhausted "totally unrecognised text"
set +e; budget_check >/dev/null 2>&1; rc=$?; set -e
check "unparseable reset PROCEEDS (never block on a guess)" "$rc" "0"

past=$(( $(date -u '+%s') - 7200 ))
printf '{"observed_at":0,"kind":"weekly","reset_epoch":%s}\n' "$past" > "$STATE"
set +e; budget_check >/dev/null 2>&1; rc=$?; set -e
check "expired reset proceeds" "$rc" "0"
check "expired state is cleared" "$([[ -f "$STATE" ]] && echo present || echo gone)" "gone"

echo ""
echo "-- gating (the case that must BLOCK) --"
future=$(( $(date -u '+%s') + 7200 ))
printf '{"observed_at":0,"kind":"weekly","reset_epoch":%s}\n' "$future" > "$STATE"
set +e; budget_check >/dev/null 2>&1; rc=$?; set -e
check "live cap returns 3" "$rc" "3"
check "live cap does NOT delete state" "$([[ -f "$STATE" ]] && echo present || echo gone)" "present"

# grep -c exits 1 on zero matches, which is a legitimate value to compare.
# silent: known-noise
msg_hits=$(budget_check 2>&1 >/dev/null | grep -c 'min remaining' || true)
check "message names the remaining time" "$msg_hits" "1"

echo ""
echo "=========================================="
echo "  Passed: $PASSED   Failed: $FAILED"
echo "=========================================="
[[ "$FAILED" -eq 0 ]] || exit 1
